import React, { useState, useEffect } from 'react';

export default function TaskForm({ initialValues, onSubmit, submitting }) {
  const [values, setValues] = useState({
    title: '', description: '', dueDate: '', priority: 'Low'
  });
  useEffect(() => {
    if (initialValues) {
      setValues({
        title: initialValues.title || '',
        description: initialValues.description || '',
        dueDate: initialValues.dueDate ? initialValues.dueDate.substring(0, 10) : '',
        priority: initialValues.priority || 'Low',
      });
    }
  }, [initialValues]);

  function handleChange(e) {
    const { name, value } = e.target;
    setValues((v) => ({ ...v, [name]: value }));
  }

  function handleSubmit(e) {
    e.preventDefault();
    onSubmit({
      title: values.title,
      description: values.description,
      dueDate: values.dueDate ? new Date(values.dueDate).toISOString() : undefined,
      priority: values.priority,
    });
  }

  return (
    <form onSubmit={handleSubmit} className="bg-white p-4 rounded border grid gap-3">
      <div>
        <label className="block text-sm font-medium">Title</label>
        <input name="title" value={values.title} onChange={handleChange} className="mt-1 w-full border rounded px-3 py-2" required />
      </div>
      <div>
        <label className="block text-sm font-medium">Description</label>
        <textarea name="description" value={values.description} onChange={handleChange} className="mt-1 w-full border rounded px-3 py-2" rows={4} />
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
        <div>
          <label className="block text-sm font-medium">Due Date</label>
          <input type="date" name="dueDate" value={values.dueDate} onChange={handleChange} className="mt-1 w-full border rounded px-3 py-2" />
        </div>
        <div>
          <label className="block text-sm font-medium">Priority</label>
          <select name="priority" value={values.priority} onChange={handleChange} className="mt-1 w-full border rounded px-3 py-2">
            <option>Low</option>
            <option>Medium</option>
            <option>High</option>
          </select>
        </div>
      </div>
      <div className="pt-2">
        <button className="px-4 py-2 bg-blue-600 text-white rounded" disabled={submitting}>
          {submitting ? 'Saving...' : 'Save Task'}
        </button>
      </div>
    </form>
  );
}
